// 沉浸式编辑器
function ImmersiveEditor\(\) {
  const [mode, setMode] = useState<'normal' | 'focus' | 'zen'>\('normal'\);
  const [isFullscreen, setIsFullscreen] = useState\(false\);

  return \(
    <div className={cn\(
